const FAQ_F=[{q:"Are your films free to watch?",a:"Yes \u2014 every Frame x Frame film is on YouTube, completely free, forever. No subscription, no paywall, no account needed."},{q:"How long are the films?",a:"Our films run between 10 and 25 minutes. We believe a space worth experiencing deserves more than a 60-second clip. We take time to tell the story properly \u2014 which is why our films retain viewers the way they do."},{q:"Where can I watch your films?",a:"All films are on our YouTube channel <strong>@weareframexframe</strong>. Browse them here on this website and click through to watch on YouTube."},{q:"How do you choose which homes to film?",a:"Mohit personally reviews every submission. We look for homes that are genuinely extraordinary \u2014 not the biggest or most expensive, but the most interesting. Homes with history, character, or a story that deserves to be told."},{q:"Who watches your films?",a:"Our audience is global \u2014 India, USA, UK, Europe, Australia, UAE, Southeast Asia and beyond. Many are architects, designers, travellers, and people who simply love beautiful spaces. Every film averages 50,000+ views."},];
const FAQ_S=[{q:"How much does it cost?",a:"Filming with Frame x Frame involves a fee. We share full details personally after reviewing and selecting your submission. Every space is different \u2014 location, travel required, and shoot complexity all factor in."},{q:"Will my film reach people outside India?",a:"Yes \u2014 definitively. Our films reach the USA, UK, Europe, Australia, UAE, and Southeast Asia. When your space is featured, it gets seen by a global audience of architecture and design lovers."},{q:"How long does filming take?",a:"We spend 1\u20132 full days at the location. We film at different times of day to capture changing light. We never rush \u2014 that's what makes the films look the way they do."},{q:"Can I submit if my home is outside the Himalayas?",a:"Absolutely. We film across India \u2014 Goa, Kerala, Rajasthan, Karnataka, the Northeast, and beyond. Location is not the criterion. Story is."},{q:"How long until my film is published after the shoot?",a:"Post-production takes 4\u20138 weeks. Editing, colour grading, sound design, and narration all require time and care \u2014 because we want the final film to feel cinematic, not rushed."},{q:"Do I get a copy of the film?",a:"Yes. You receive the full film file after it is published on YouTube. The film remains on the Frame x Frame channel permanently \u2014 free to watch forever."},{q:"Can hotels and resorts also submit?",a:"Yes \u2014 boutique hotels, jungle lodges, mountain resorts, and extraordinary Airbnbs are very welcome. If your hospitality space has a soul and a story, we want to film it."},];

function th(id,q){return`https://img.youtube.com/vi/${id}/${q}.jpg`;}

function card(f,idx){
  return`<div class="fcard" onclick="openFilm(${idx})">
    <div class="fcard-img">
      <img src="${th(f.id,'maxresdefault')}" alt="${f.title}" loading="lazy"
        onerror="this.src=th(f.id,'hqdefault');this.onerror=function(){this.style.display='none';this.nextElementSibling.classList.add('show');}">
      <div class="fcard-fb"><div class="fcard-fb-play"><div class="fcard-fb-arr"></div></div><div class="fcard-fb-t">${f.title}</div></div>
      <div class="fcard-ov"><div class="fcard-play"><div class="fcard-arr"></div></div></div>
    </div>
    <div class="fcard-body">
      <div class="fcard-tag">${f.tag}</div>
      <div class="fcard-title serif">${f.title}</div>
      <div class="fcard-loc">${f.loc}</div>
    </div>
  </div>`;
}

function renderGrids(){
  const hg=document.getElementById('hg');
  const lg=document.getElementById('lg');
  if(hg)hg.innerHTML=FILMS.map((f,i)=>card(f,i)).join('');
  if(lg)lg.innerHTML=FILMS.map((f,i)=>card(f,i)).join('');
}

let ytCur='';
function openYT(){window.open('https://www.youtube.com/watch?v='+ytCur,'_blank','noopener');}

function openFilm(idx){
  const f=FILMS[idx];
  ytCur=f.id;
  document.getElementById('fp-eye').textContent=f.tag;
  document.getElementById('fp-h1').textContent=f.title;
  document.getElementById('fp-loc').textContent=f.loc;
  const img=document.getElementById('fp-img');
  img.src=th(f.id,'maxresdefault');
  img.alt=f.title;
  img.onerror=()=>{img.src=th(f.id,'hqdefault');img.onerror=()=>{img.src=th(f.id,'mqdefault');};}; 
  if (f.article) {
    document.getElementById('fp-story').innerHTML=`
      ${f.article}
      <br>
      <p>Watch the full film free on YouTube: <a href="https://www.youtube.com/watch?v=${f.id}" target="_blank" rel="noopener">@weareframexframe →</a></p>`;
  } else {
    document.getElementById('fp-story').innerHTML=`
      <h2 class="serif">${f.sub}</h2>
      <p>${f.desc}</p>
      <p>This film is part of Frame x Frame's ongoing documentary series exploring India's most extraordinary homes. Directed by Mohit, every film is researched, scouted, and shot over multiple days — because a space worth experiencing deserves more than a rushed shoot.</p>
      <blockquote class="serif">"This isn't marketing. It's memory-making."</blockquote>
      <p>Watch the full film free on YouTube: <a href="https://www.youtube.com/watch?v=${f.id}" target="_blank" rel="noopener">@weareframexframe →</a></p>`;
  }
  document.getElementById('fp-details').innerHTML=`
    <h4>Film Details</h4>
    <div class="fp-row"><span>Location</span><span>${f.loc}</span></div>
    <div class="fp-row"><span>Type</span><span>${f.tag}</span></div>
    <div class="fp-row"><span>Year</span><span>${f.year}</span></div>
    <div class="fp-row"><span>Director</span><span>Mohit</span></div>
    <div class="fp-row"><span>Watch</span><span><a href="https://www.youtube.com/watch?v=${f.id}" target="_blank" rel="noopener" style="color:var(--blue)">YouTube →</a></span></div>`;
  const rel=FILMS.filter((_,i)=>i!==idx).slice(0,3);
  document.getElementById('fp-rel').innerHTML=rel.map(r=>card(r,FILMS.indexOf(r))).join('');
  go('film');
}

let cur='home';
function go(page){
  document.querySelectorAll('.pg').forEach(p=>p.classList.remove('on'));
  const el=document.getElementById('p-'+page);
  if(el)el.classList.add('on');
  cur=page;
  window.scrollTo({top:0,behavior:'instant'});
  updNav(page,0);
  document.getElementById('mob').style.display='none';
  setTimeout(doReveal,90);
}

function updNav(page,sy){
  const nav=document.getElementById('nav');
  const logo=document.getElementById('nl');
  const dark=(page==='home'&&sy<60)||(page!=='home'&&sy<24);
  nav.className=dark?'clr':'wht';
  logo.src=dark?LW:LB;
  // always set footer logos white
  document.querySelectorAll('.fli').forEach(i=>i.src=LW);
}

window.addEventListener('scroll',()=>updNav(cur,window.scrollY),{passive:true});

function mobToggle(){
  const m=document.getElementById('mob');
  m.style.display=m.style.display==='block'?'none':'block';
}

function submitFYS(){document.getElementById('fys-ok').style.display='block';}
function submitContact(){document.getElementById('c-ok').style.display='block';}

let rObs=null;
function doReveal(){
  if(rObs)rObs.disconnect();
  rObs=new IntersectionObserver(entries=>{
    entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('vis');rObs.unobserve(e.target);}});
  },{threshold:.07});
  document.querySelectorAll('#p-'+cur+' .reveal:not(.vis)').forEach(el=>rObs.observe(el));
}

function buildFAQ(items,cid){
  const c=document.getElementById(cid);
  if(!c)return;
  c.innerHTML=items.map((f,i)=>{
    const id=`fq-${cid}-${i}`;
    return`<div class="faq-item" id="${id}">
      <div class="faq-q" onclick="faqToggle('${id}')">
        <span class="faq-q-t">${f.q}</span><span class="faq-icon">+</span>
      </div>
      <div class="faq-a"><div class="faq-a-inner">${f.a}</div></div>
    </div>`;
  }).join('');
}

function faqToggle(id){
  const el=document.getElementById(id);
  const was=el.classList.contains('open');
  document.querySelectorAll('.faq-item.open').forEach(i=>i.classList.remove('open'));
  if(!was)el.classList.add('open');
}

document.addEventListener('DOMContentLoaded',()=>{
  // set all footer logos to white immediately
  document.querySelectorAll('.fli').forEach(i=>i.src=LW);
  renderGrids();
  buildFAQ(FAQ_F,'faq-f');
  buildFAQ(FAQ_S,'faq-s');
  doReveal();
});

(function(){
  var cur=0,timer=null,DUR=8000;
  function getSl(){return document.querySelectorAll('.hero-slide');}
  function getDt(){return document.querySelectorAll('.hero-dot');}
  function goSlide(n){
    var sl=getSl(),dt=getDt();
    sl[cur].classList.remove('active');
    sl[cur].classList.add('leaving');
    var lv=sl[cur];
    setTimeout(function(){lv.classList.remove('leaving');},950);
    cur=((n%sl.length)+sl.length)%sl.length;
    sl[cur].classList.add('active');
    dt.forEach(function(d,i){d.classList.toggle('on',i===cur);});
    clearInterval(timer);
    timer=setInterval(function(){goSlide(cur+1);},DUR);
  }
  window.goSlide=goSlide;
  document.addEventListener('DOMContentLoaded',function(){
    timer=setInterval(function(){goSlide(cur+1);},DUR);
  });
})();